"use client";

import { useEffect, useState, useCallback } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Slider } from "@/components/ui/slider";
import { 
  Settings, Cpu, Mic, Gauge, FileText, Save, 
  Loader2, CheckCircle2, AlertCircle, Zap, Brain, 
  Volume2, Clock, Target 
} from "lucide-react";
import { toast } from "sonner";

interface SettingRow {
  key: string;
  value: string;
  category: string;
  label: string;
  description: string;
  updated_at: string;
}

// Known model options for dropdowns
const LLM_PROVIDERS = [
  { value: "groq", label: "Groq", description: "Ultra-fast inference" },
  { value: "openrouter", label: "OpenRouter", description: "Multi-model gateway" },
];

const GROQ_MODELS = [
  { value: "openai/gpt-oss-120b", label: "GPT-OSS 120B" },
  { value: "openai/gpt-oss-safeguard-20b", label: "GPT-OSS Safeguard 20B" },
  { value: "llama-3.3-70b-versatile", label: "Llama 3.3 70B Versatile" },
  { value: "llama-3.1-8b-instant", label: "Llama 3.1 8B Instant" },
  { value: "mixtral-8x7b-32768", label: "Mixtral 8x7B" },
  { value: "gemma2-9b-it", label: "Gemma 2 9B" },
];

const OPENROUTER_MODELS = [
  { value: "x-ai/grok-4.1-fast", label: "Grok 4.1 Fast" },
  { value: "anthropic/claude-sonnet-4", label: "Claude Sonnet 4" },
  { value: "google/gemini-2.5-pro", label: "Gemini 2.5 Pro" },
  { value: "openai/gpt-4o", label: "GPT-4o" },
  { value: "meta-llama/llama-3.3-70b-instruct", label: "Llama 3.3 70B" },
];

const VOICE_PROVIDERS = [
  { value: "groq", label: "Groq", description: "Fast Whisper inference" },
  { value: "openai", label: "OpenAI", description: "Original Whisper" },
];

const VOICE_MODELS = [
  { value: "whisper-large-v3-turbo", label: "Whisper V3 Turbo" },
  { value: "whisper-large-v3", label: "Whisper Large V3" },
];

const LANGUAGES = [
  { value: "pt", label: "Português" },
  { value: "en", label: "English" },
  { value: "es", label: "Español" },
  { value: "fr", label: "Français" },
  { value: "auto", label: "Auto-detect" },
];

export default function AdminSettingsPage() {
  const [settings, setSettings] = useState<Record<string, string>>({});
  const [originalSettings, setOriginalSettings] = useState<Record<string, string>>({});
  const [settingsMeta, setSettingsMeta] = useState<Record<string, SettingRow>>({});
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [hasChanges, setHasChanges] = useState(false);

  // Fetch settings on mount
  useEffect(() => {
    async function fetchSettings() {
      try {
        const res = await fetch("/api/settings");
        if (!res.ok) throw new Error("Failed to fetch");
        const data: SettingRow[] = await res.json();

        const map: Record<string, string> = {};
        const meta: Record<string, SettingRow> = {};
        data.forEach((s) => {
          map[s.key] = s.value;
          meta[s.key] = s;
        });
        setSettings(map);
        setOriginalSettings(map);
        setSettingsMeta(meta);
      } catch (err) {
        console.error("Failed to load settings:", err);
        toast.error("Failed to load settings");
      } finally {
        setIsLoading(false);
      }
    }
    fetchSettings();
  }, []);

  // Track changes
  useEffect(() => {
    const changed = Object.keys(settings).some(
      (key) => settings[key] !== originalSettings[key]
    );
    setHasChanges(changed);
  }, [settings, originalSettings]);

  const updateSetting = useCallback((key: string, value: string) => {
    setSettings((prev) => ({ ...prev, [key]: value }));
  }, []);

  const handleSave = async () => {
    setIsSaving(true);
    try {
      const changedSettings = Object.keys(settings)
        .filter((key) => settings[key] !== originalSettings[key])
        .map((key) => ({ key, value: settings[key] }));

      if (changedSettings.length === 0) return;

      const res = await fetch("/api/settings", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ settings: changedSettings }),
      });

      if (!res.ok) throw new Error("Save failed");

      setOriginalSettings({ ...settings });
      setHasChanges(false);
      toast.success("Settings saved successfully!", {
        description: `${changedSettings.length} setting(s) updated`,
      });
    } catch (err) {
      toast.error("Failed to save settings");
    } finally {
      setIsSaving(false);
    }
  };

  const handleReset = () => {
    setSettings({ ...originalSettings });
  };

  // Get correct LLM models based on selected provider
  const llmModels = settings.ai_llm_provider === "openrouter" 
    ? OPENROUTER_MODELS 
    : GROQ_MODELS;

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-[60vh] gap-3">
        <Loader2 className="w-6 h-6 animate-spin text-purple-400" />
        <span className="text-zinc-400 text-lg">Loading settings...</span>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-700 max-w-4xl">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold tracking-tight bg-gradient-to-r from-purple-300 to-indigo-300 bg-clip-text text-transparent">
            Global AI Configuration
          </h2>
          <p className="text-zinc-400 mt-2">
            Configure AI providers, models, performance, and briefing parameters for all users.
          </p>
        </div>

        {/* Save Button */}
        <div className="flex items-center gap-3">
          {hasChanges && (
            <Button
              variant="ghost"
              onClick={handleReset}
              className="text-zinc-400 hover:text-zinc-200"
            >
              Undo
            </Button>
          )}
          <Button
            onClick={handleSave}
            disabled={!hasChanges || isSaving}
            className={`rounded-xl px-6 h-11 transition-all ${
              hasChanges
                ? "bg-purple-600 hover:bg-purple-500 text-white shadow-[0_0_20px_-5px_rgba(147,51,234,0.5)]"
                : "bg-zinc-800 text-zinc-500 cursor-not-allowed"
            }`}
          >
            {isSaving ? (
              <Loader2 className="w-4 h-4 mr-2 animate-spin" />
            ) : hasChanges ? (
              <Save className="w-4 h-4 mr-2" />
            ) : (
              <CheckCircle2 className="w-4 h-4 mr-2" />
            )}
            {isSaving ? "Saving..." : hasChanges ? "Save Changes" : "Saved"}
          </Button>
        </div>
      </div>

      {/* Tabs */}
      <Tabs defaultValue="ai" className="w-full">
        <TabsList className="bg-zinc-900/80 border border-purple-500/10 rounded-xl p-1 h-auto flex-wrap">
          <TabsTrigger value="ai" className="rounded-lg data-[state=active]:bg-purple-500/10 data-[state=active]:text-purple-300 px-4 py-2.5 gap-2">
            <Brain className="w-4 h-4" />
            <span className="hidden sm:inline">Intelligence</span>
            <span className="sm:hidden">AI</span>
          </TabsTrigger>
          <TabsTrigger value="voice" className="rounded-lg data-[state=active]:bg-purple-500/10 data-[state=active]:text-purple-300 px-4 py-2.5 gap-2">
            <Volume2 className="w-4 h-4" />
            Voice
          </TabsTrigger>
          <TabsTrigger value="performance" className="rounded-lg data-[state=active]:bg-purple-500/10 data-[state=active]:text-purple-300 px-4 py-2.5 gap-2">
            <Gauge className="w-4 h-4" />
            <span className="hidden sm:inline">Performance</span>
            <span className="sm:hidden">Perf</span>
          </TabsTrigger>
          <TabsTrigger value="briefing" className="rounded-lg data-[state=active]:bg-purple-500/10 data-[state=active]:text-purple-300 px-4 py-2.5 gap-2">
            <Target className="w-4 h-4" />
            <span className="hidden sm:inline">Briefing</span>
            <span className="sm:hidden">Brief</span>
          </TabsTrigger>
        </TabsList>

        {/* TAB: AI / LLM */}
        <TabsContent value="ai" className="mt-6 space-y-6">
          <Card className="bg-zinc-900/50 backdrop-blur-md border-purple-500/10">
            <CardHeader className="pb-4">
              <CardTitle className="text-lg flex items-center gap-3">
                <div className="p-2 rounded-xl bg-purple-500/10 border border-purple-500/20">
                  <Cpu className="w-5 h-5 text-purple-400" />
                </div>
                LLM Provider
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">
              {/* Provider */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-zinc-300 text-sm font-medium">Provider</Label>
                  <Select 
                    value={settings.ai_llm_provider || "groq"} 
                    onValueChange={(v) => {
                      updateSetting("ai_llm_provider", v || "");
                      // Reset model when changing provider
                      if (v === "groq") updateSetting("ai_llm_model", "openai/gpt-oss-120b");
                      if (v === "openrouter") updateSetting("ai_llm_model", "x-ai/grok-4.1-fast");
                    }}
                  >
                    <SelectTrigger className="bg-black/40 border-white/10 h-12 rounded-xl text-white">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-zinc-900 border-white/10">
                      {LLM_PROVIDERS.map(p => (
                        <SelectItem key={p.value} value={p.value} className="text-white focus:bg-purple-500/10 focus:text-purple-300">
                          <div className="flex items-center gap-2">
                            <Zap className="w-3.5 h-3.5 text-purple-400" />
                            <span>{p.label}</span>
                            <span className="text-zinc-500 text-xs">— {p.description}</span>
                          </div>
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                {/* Model */}
                <div className="space-y-2">
                  <Label className="text-zinc-300 text-sm font-medium">Model</Label>
                  <Select 
                    value={settings.ai_llm_model || ""} 
                    onValueChange={(v) => updateSetting("ai_llm_model", v || "")}
                  >
                    <SelectTrigger className="bg-black/40 border-white/10 h-12 rounded-xl text-white">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-zinc-900 border-white/10">
                      {llmModels.map(m => (
                        <SelectItem key={m.value} value={m.value} className="text-white focus:bg-purple-500/10 focus:text-purple-300">
                          {m.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <p className="text-[11px] text-zinc-500">
                    Or type a custom model below
                  </p>
                  <Input
                    value={settings.ai_llm_model || ""}
                    onChange={(e) => updateSetting("ai_llm_model", e.target.value)}
                    placeholder="e.g. openai/gpt-oss-120b"
                    className="bg-black/40 border-white/10 rounded-xl h-10 text-white font-mono text-sm"
                  />
                </div>
              </div>

              <Separator className="bg-white/5" />

              {/* Temperature */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <Label className="text-zinc-300 text-sm font-medium">
                    Temperature
                  </Label>
                  <span className="text-purple-400 font-mono text-sm font-bold bg-purple-500/10 px-3 py-1 rounded-lg">
                    {settings.ai_llm_temperature || "0"}
                  </span>
                </div>
                <Slider
                  value={[parseFloat(settings.ai_llm_temperature || "0")]}
                  onValueChange={(v) => updateSetting("ai_llm_temperature", (v as number[])[0].toFixed(1))}
                  max={1}
                  min={0}
                  step={0.1}
                  className="w-full"
                />
                <div className="flex justify-between text-[11px] text-zinc-500">
                  <span>Deterministic (0)</span>
                  <span>Creative (1)</span>
                </div>
              </div>

              {/* Max Tokens */}
              <div className="space-y-2">
                <Label className="text-zinc-300 text-sm font-medium">Max Tokens</Label>
                <Input
                  type="number"
                  value={settings.ai_llm_max_tokens || "1200"}
                  onChange={(e) => updateSetting("ai_llm_max_tokens", e.target.value)}
                  min={200}
                  max={8000}
                  className="bg-black/40 border-white/10 rounded-xl h-12 text-white font-mono"
                />
                <p className="text-[11px] text-zinc-500">
                  Maximum tokens in the response. More tokens = longer but slower.
                </p>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* TAB: VOICE */}
        <TabsContent value="voice" className="mt-6 space-y-6">
          <Card className="bg-zinc-900/50 backdrop-blur-md border-purple-500/10">
            <CardHeader className="pb-4">
              <CardTitle className="text-lg flex items-center gap-3">
                <div className="p-2 rounded-xl bg-indigo-500/10 border border-indigo-500/20">
                  <Mic className="w-5 h-5 text-indigo-400" />
                </div>
                Voice Transcription (STT)
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-zinc-300 text-sm font-medium">Provider</Label>
                  <Select 
                    value={settings.ai_voice_provider || "groq"} 
                    onValueChange={(v) => updateSetting("ai_voice_provider", v || "")}
                  >
                    <SelectTrigger className="bg-black/40 border-white/10 h-12 rounded-xl text-white">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-zinc-900 border-white/10">
                      {VOICE_PROVIDERS.map(p => (
                        <SelectItem key={p.value} value={p.value} className="text-white focus:bg-indigo-500/10 focus:text-indigo-300">
                          <div className="flex items-center gap-2">
                            <Volume2 className="w-3.5 h-3.5 text-indigo-400" />
                            <span>{p.label}</span>
                            <span className="text-zinc-500 text-xs">— {p.description}</span>
                          </div>
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label className="text-zinc-300 text-sm font-medium">Model</Label>
                  <Select 
                    value={settings.ai_voice_model || "whisper-large-v3-turbo"} 
                    onValueChange={(v) => updateSetting("ai_voice_model", v || "")}
                  >
                    <SelectTrigger className="bg-black/40 border-white/10 h-12 rounded-xl text-white">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-zinc-900 border-white/10">
                      {VOICE_MODELS.map(m => (
                        <SelectItem key={m.value} value={m.value} className="text-white focus:bg-indigo-500/10 focus:text-indigo-300">
                          {m.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <Separator className="bg-white/5" />

              <div className="space-y-2">
                <Label className="text-zinc-300 text-sm font-medium">Default Transcription Language</Label>
                <Select 
                  value={settings.ai_voice_language || "pt"} 
                  onValueChange={(v) => updateSetting("ai_voice_language", v || "")}
                >
                  <SelectTrigger className="bg-black/40 border-white/10 h-12 rounded-xl text-white max-w-xs">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="bg-zinc-900 border-white/10">
                    {LANGUAGES.map(l => (
                      <SelectItem key={l.value} value={l.value} className="text-white focus:bg-indigo-500/10 focus:text-indigo-300">
                        {l.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <p className="text-[11px] text-zinc-500">
                  Language used for audio transcription when not specified.
                </p>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* TAB: PERFORMANCE */}
        <TabsContent value="performance" className="mt-6 space-y-6">
          <Card className="bg-zinc-900/50 backdrop-blur-md border-purple-500/10">
            <CardHeader className="pb-4">
              <CardTitle className="text-lg flex items-center gap-3">
                <div className="p-2 rounded-xl bg-amber-500/10 border border-amber-500/20">
                  <Gauge className="w-5 h-5 text-amber-400" />
                </div>
                Performance & Speed
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div>
                    <Label className="text-zinc-300 text-sm font-medium">History Messages</Label>
                    <p className="text-[11px] text-zinc-500 mt-1">
                      How many previous messages to send to the AI per request.
                    </p>
                  </div>
                  <span className="text-amber-400 font-mono text-sm font-bold bg-amber-500/10 px-3 py-1 rounded-lg">
                    {settings.briefing_max_history || "6"}
                  </span>
                </div>
                <Slider
                  value={[parseInt(settings.briefing_max_history || "6")]}
                  onValueChange={(v) => updateSetting("briefing_max_history", String((v as number[])[0]))}
                  max={20}
                  min={2}
                  step={1}
                  className="w-full"
                />
                <div className="flex justify-between text-[11px] text-zinc-500">
                  <span>Minimum (2) — Faster</span>
                  <span>Maximum (20) — More context</span>
                </div>
              </div>

              <Separator className="bg-white/5" />

              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div>
                    <Label className="text-zinc-300 text-sm font-medium">Request Timeout</Label>
                    <p className="text-[11px] text-zinc-500 mt-1">
                      Maximum wait time (ms) before aborting the AI call.
                    </p>
                  </div>
                  <span className="text-amber-400 font-mono text-sm font-bold bg-amber-500/10 px-3 py-1 rounded-lg">
                    {(parseInt(settings.briefing_timeout_ms || "30000") / 1000).toFixed(0)}s
                  </span>
                </div>
                <Slider
                  value={[parseInt(settings.briefing_timeout_ms || "30000")]}
                  onValueChange={(v) => updateSetting("briefing_timeout_ms", String((v as number[])[0]))}
                  max={60000}
                  min={5000}
                  step={5000}
                  className="w-full"
                />
                <div className="flex justify-between text-[11px] text-zinc-500">
                  <span>5s — Aggressive</span>
                  <span>60s — Patient</span>
                </div>
              </div>

              {/* Speed Tips */}
              <div className="rounded-xl bg-amber-500/5 border border-amber-500/20 p-4 flex gap-3">
                <Zap className="w-5 h-5 text-amber-400 shrink-0 mt-0.5" />
                <div className="text-sm text-zinc-300">
                  <p className="font-medium text-amber-300 mb-1">Speed Tips</p>
                  <ul className="text-zinc-400 space-y-1 text-xs">
                    <li>• Use <strong className="text-zinc-300">Groq</strong> as provider for ultra-fast inference</li>
                    <li>• <strong className="text-zinc-300">Temperature 0</strong> eliminates random sampling</li>
                    <li>• Fewer history messages = fewer tokens = faster</li>
                    <li>• Aggressive timeout (10-15s) prevents hangs</li>
                  </ul>
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* TAB: BRIEFING */}
        <TabsContent value="briefing" className="mt-6 space-y-6">
          <Card className="bg-zinc-900/50 backdrop-blur-md border-purple-500/10">
            <CardHeader className="pb-4">
              <CardTitle className="text-lg flex items-center gap-3">
                <div className="p-2 rounded-xl bg-emerald-500/10 border border-emerald-500/20">
                  <Target className="w-5 h-5 text-emerald-400" />
                </div>
                Briefing Parameters
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div>
                    <Label className="text-zinc-300 text-sm font-medium">Basal Coverage Threshold</Label>
                    <p className="text-[11px] text-zinc-500 mt-1">
                      Minimum percentage of required fields to finalize the briefing.
                    </p>
                  </div>
                  <span className="text-emerald-400 font-mono text-sm font-bold bg-emerald-500/10 px-3 py-1 rounded-lg">
                    {Math.round(parseFloat(settings.briefing_basal_threshold || "0.85") * 100)}%
                  </span>
                </div>
                <Slider
                  value={[parseFloat(settings.briefing_basal_threshold || "0.85")]}
                  onValueChange={(v) => updateSetting("briefing_basal_threshold", (v as number[])[0].toFixed(2))}
                  max={1}
                  min={0.5}
                  step={0.05}
                  className="w-full"
                />
                <div className="flex justify-between text-[11px] text-zinc-500">
                  <span>50% — Permissive</span>
                  <span>100% — Strict</span>
                </div>
              </div>

              {/* Info card */}
              <div className="rounded-xl bg-emerald-500/5 border border-emerald-500/20 p-4 flex gap-3">
                <AlertCircle className="w-5 h-5 text-emerald-400 shrink-0 mt-0.5" />
                <div className="text-sm text-zinc-400">
                  <p className="font-medium text-emerald-300 mb-1">About Basal Coverage</p>
                  <p className="text-xs">
                    The AI only advances to visual questions (colors, style, logo) when this threshold 
                    is met. A higher value ensures the AI extracts more business information 
                    before making aesthetic suggestions.
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Mobile-sticky save bar */}
      {hasChanges && (
        <div className="fixed bottom-0 left-0 right-0 md:hidden bg-black/80 backdrop-blur-xl border-t border-purple-500/10 p-4 z-50">
          <Button
            onClick={handleSave}
            disabled={isSaving}
            className="w-full h-12 rounded-xl bg-purple-600 hover:bg-purple-500 text-white font-semibold shadow-[0_0_20px_-5px_rgba(147,51,234,0.5)]"
          >
            {isSaving ? (
              <Loader2 className="w-4 h-4 mr-2 animate-spin" />
            ) : (
              <Save className="w-4 h-4 mr-2" />
            )}
            {isSaving ? "Saving..." : "Save Changes"}
          </Button>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter, useParams } from 'next/navigation';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { ArrowLeft, Save, Loader2, Ban, CheckCircle2, FileText, AlertCircle } from 'lucide-react';
import Link from 'next/link';
import { createClient } from '@/lib/supabase/client';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';

interface UserData {
  id: string;
  display_name: string;
  company_name: string;
  plan: string;
  created_at: string;
}

interface QuotaData {
  max_briefings: number;
  used_briefings: number;
  is_blocked: boolean;
  blocked_reason: string;
}

export default function AdminUserDetailPage() {
  const router = useRouter();
  const params = useParams();
  const userId = params.id as string;

  const [user, setUser] = useState<UserData | null>(null);
  const [quota, setQuota] = useState<QuotaData | null>(null);
  const [sessions, setSessions] = useState<{ id: string; session_name: string; status: string; created_at: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [maxBriefings, setMaxBriefings] = useState(10);
  const [isBlocked, setIsBlocked] = useState(false);
  const [blockedReason, setBlockedReason] = useState('');
  const [plan, setPlan] = useState('free');

  useEffect(() => {
    async function loadUser() {
      const supabase = createClient();

      const { data: profile } = await supabase
        .from('briefing_profiles')
        .select('*')
        .eq('id', userId)
        .single();

      const { data: quotaData } = await supabase
        .from('briefing_quotas')
        .select('*')
        .eq('user_id', userId)
        .single();

      const { data: sessionsData } = await supabase
        .from('briefing_sessions')
        .select('id, session_name, status, created_at')
        .eq('user_id', userId)
        .order('created_at', { ascending: false });

      if (profile) setUser(profile);
      if (quotaData) {
        setQuota(quotaData);
        setMaxBriefings(quotaData.max_briefings);
        setIsBlocked(quotaData.is_blocked);
        setBlockedReason(quotaData.blocked_reason || '');
      }
      if (sessionsData) setSessions(sessionsData);
      if (profile) setPlan(profile.plan || 'free');

      setLoading(false);
    }
    loadUser();
  }, [userId]);

  const handleSave = async () => {
    setSaving(true);
    try {
      const supabase = createClient();

      await supabase
        .from('briefing_quotas')
        .update({
          max_briefings: maxBriefings,
          is_blocked: isBlocked,
          blocked_reason: isBlocked ? blockedReason : '',
          updated_at: new Date().toISOString(),
        })
        .eq('user_id', userId);

      await supabase
        .from('briefing_profiles')
        .update({ plan, updated_at: new Date().toISOString() })
        .eq('id', userId);

      router.refresh();
    } catch (err) {
      console.error('Error saving:', err);
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[50vh]">
        <Loader2 className="w-8 h-8 animate-spin text-purple-400" />
      </div>
    );
  }

  if (!user) {
    return <p className="text-zinc-500 text-center py-20">User not found.</p>;
  }

  return (
    <div className="space-y-8 max-w-3xl animate-in fade-in duration-700">
      <div>
        <Link href="/admin">
          <Button variant="ghost" className="text-zinc-400 hover:text-white -ml-4 mb-4">
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Users
          </Button>
        </Link>
        <h2 className="text-2xl md:text-3xl font-bold tracking-tight text-white">
          {user.display_name}
        </h2>
        <p className="text-zinc-400 text-sm mt-1">{user.company_name || 'No company'} • Joined {new Date(user.created_at).toLocaleDateString()}</p>
      </div>

      {/* Quota Management */}
      <Card className="bg-zinc-900/50 border-purple-500/10">
        <CardHeader>
          <CardTitle className="text-purple-300">Quota & Plan Management</CardTitle>
          <CardDescription className="text-zinc-400">
            Control how many briefings this user can create.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <Label className="text-zinc-300">Max Briefings</Label>
              <Input
                type="number"
                value={maxBriefings}
                onChange={(e) => setMaxBriefings(parseInt(e.target.value) || 0)}
                className="bg-black/50 border-white/10 focus-visible:ring-purple-500"
              />
              <p className="text-xs text-zinc-500">Currently used: {quota?.used_briefings || 0}</p>
            </div>

            <div className="space-y-2">
              <Label className="text-zinc-300">Plan</Label>
              <Select value={plan} onValueChange={(v) => setPlan(v || 'free')}>
                <SelectTrigger className="bg-black/50 border-white/10">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="bg-zinc-900 border-zinc-800">
                  <SelectItem value="free">Free</SelectItem>
                  <SelectItem value="pro">Pro</SelectItem>
                  <SelectItem value="enterprise">Enterprise</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="space-y-3 p-4 rounded-xl border border-red-900/30 bg-red-950/20">
            <div className="flex items-center gap-3">
              <Button
                variant={isBlocked ? 'destructive' : 'outline'}
                size="sm"
                onClick={() => setIsBlocked(!isBlocked)}
                className={!isBlocked ? 'border-red-900/50 text-red-400 hover:bg-red-950/50' : ''}
              >
                {isBlocked ? <CheckCircle2 className="w-4 h-4 mr-2" /> : <Ban className="w-4 h-4 mr-2" />}
                {isBlocked ? 'User is BLOCKED' : 'Block User'}
              </Button>
            </div>
            {isBlocked && (
              <div className="space-y-2">
                <Label className="text-red-300 text-sm">Block Reason</Label>
                <Input
                  value={blockedReason}
                  onChange={(e) => setBlockedReason(e.target.value)}
                  placeholder="Reason for blocking..."
                  className="bg-black/50 border-red-900/30 focus-visible:ring-red-500"
                />
              </div>
            )}
          </div>

          <Button onClick={handleSave} disabled={saving} className="bg-purple-600 hover:bg-purple-500">
            {saving ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
            Save Changes
          </Button>
        </CardContent>
      </Card>

      {/* User's Briefings */}
      <div className="space-y-4">
        <h3 className="text-lg font-semibold text-zinc-100 flex items-center gap-2">
          <FileText className="w-5 h-5 text-purple-400" />
          User&apos;s Briefings ({sessions.length})
        </h3>
        {sessions.length === 0 ? (
          <Card className="bg-zinc-900/30 border-white/5">
            <CardContent className="text-center py-8 text-zinc-500">
              No briefings created by this user.
            </CardContent>
          </Card>
        ) : (
          <div className="space-y-2">
            {sessions.map(s => (
              <Card key={s.id} className="bg-zinc-900/40 border-white/8">
                <CardContent className="py-3 px-4 flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-zinc-200">{s.session_name || 'Untitled'}</p>
                    <p className="text-xs text-zinc-500">{new Date(s.created_at).toLocaleDateString()}</p>
                  </div>
                  <span className={`text-xs px-2 py-0.5 rounded-full border ${
                    s.status === 'finished' ? 'text-emerald-400 bg-emerald-400/10 border-emerald-400/20' :
                    s.status === 'in_progress' ? 'text-amber-400 bg-amber-400/10 border-amber-400/20' :
                    'text-zinc-400 bg-zinc-400/10 border-zinc-400/20'
                  }`}>
                    {s.status}
                  </span>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { NextResponse } from "next/server";
import { createClient } from "@supabase/supabase-js";

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;
const supabase = createClient(supabaseUrl, supabaseKey);

// GET - List all packages (ordered by sort_order)
export async function GET() {
  try {
    const { data, error } = await supabase
      .from("briefing_category_packages")
      .select("*")
      .order("sort_order", { ascending: true });

    if (error) throw error;

    return NextResponse.json(data);
  } catch (error: any) {
    console.error("Error fetching packages:", error.message || error);
    return NextResponse.json(
      { error: "Failed to fetch packages", details: error.message || '' },
      { status: 500 }
    );
  }
}

// POST - Create a new package (admin)
export async function POST(req: Request) {
  try {
    const body = await req.json();
    const { slug, name, description, icon, system_prompt_fragment, max_questions, is_default_enabled, sort_order, department } = body;

    if (!slug || !name) {
      return NextResponse.json({ error: "slug and name are required" }, { status: 400 });
    }

    const { data, error } = await supabase
      .from("briefing_category_packages")
      .insert([{
        slug,
        name,
        description: description || "",
        icon: icon || "Package",
        system_prompt_fragment: system_prompt_fragment || "",
        max_questions: max_questions ?? 10,
        is_default_enabled: is_default_enabled ?? false,
        sort_order: sort_order ?? 0,
        department: department || "general",
      }])
      .select()
      .single();

    if (error) throw error;

    return NextResponse.json(data);
  } catch (error) {
    console.error("Error creating package:", error);
    return NextResponse.json(
      { error: "Failed to create package" },
      { status: 500 }
    );
  }
}

// PUT - Update a package (admin)
export async function PUT(req: Request) {
  try {
    const body = await req.json();
    const { id, ...updates } = body;

    if (!id) {
      return NextResponse.json({ error: "id is required" }, { status: 400 });
    }

    const { data, error } = await supabase
      .from("briefing_category_packages")
      .update({ ...updates, updated_at: new Date().toISOString() })
      .eq("id", id)
      .select()
      .single();

    if (error) throw error;

    return NextResponse.json(data);
  } catch (error) {
    console.error("Error updating package:", error);
    return NextResponse.json(
      { error: "Failed to update package" },
      { status: 500 }
    );
  }
}

// DELETE - Delete a package (admin)
export async function DELETE(req: Request) {
  try {
    const { searchParams } = new URL(req.url);
    const id = searchParams.get("id");

    if (!id) {
      return NextResponse.json({ error: "id is required" }, { status: 400 });
    }

    const { error } = await supabase
      .from("briefing_category_packages")
      .delete()
      .eq("id", id);

    if (error) throw error;

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error("Error deleting package:", error);
    return NextResponse.json(
      { error: "Failed to delete package" },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { getLLMConfig, getDBSettings, getPerformanceConfig } from "@/lib/aiConfig";
import { createClient } from "@supabase/supabase-js";

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;
const supabaseServer = createClient(supabaseUrl, supabaseKey);

// ================================================================
// BUILD PACKAGE PROMPTS — Fetch & Concatenate Active Skill Fragments
// ================================================================
async function buildPackagePrompts(selectedSlugs?: string[]): Promise<string> {
  if (!selectedSlugs || selectedSlugs.length === 0) return '';

  try {
    const { data: packages, error } = await supabaseServer
      .from('briefing_category_packages')
      .select('slug, name, system_prompt_fragment, max_questions')
      .in('slug', selectedSlugs);

    if (error || !packages || packages.length === 0) return '';

    const fragments = packages.map((pkg: { name: string; max_questions: number | null; system_prompt_fragment: string }) => {
      const limit = pkg.max_questions ? `(up to ${pkg.max_questions} unique questions)` : '(UNLIMITED questions — adapt to complexity)';
      return `[ACTIVE PACKAGE: ${pkg.name}] ${limit}\n${pkg.system_prompt_fragment}`;
    }).join('\n\n');

    return `
═══ CATEGORY PACKAGES — Active AI Specializations ═══
The following specialized skill packages are ACTIVE for this briefing session.
Each package adds unique questions for its area. CRITICAL DEDUPLICATION RULES:
1. If a question from Package A is already covered by Package B or by the universal basal fields, DO NOT ask it again.
2. Use your judgment to MERGE overlapping topics into richer, combined questions.
3. When the multi_slider type is specified in a package, you MUST generate the question using questionType "multi_slider" with the specified options format.
4. Each package's questions should be distributed across the relevant sections, not clustered together.

${fragments}
═══ END CATEGORY PACKAGES ═══`;
  } catch (err) {
    console.error('Error building package prompts:', err);
    return '';
  }
}

// ================================================================
// BASAL CONTRACT — Universal Fields (independent of template)
// ================================================================
const UNIVERSAL_BASAL_FIELDS = [
  "company_name",
  "sector_segment",
  "company_age",
  "services_offered",
  "owner_relationship",
  "brand_name_meaning",
  "keywords",
  "mission_vision_values",
  "target_audience_demographics",
  "competitors",
  "competitive_differentiator",
  "communication_channels",
  "geographic_reach",
  "brand_personality",
  "tone_of_voice"
];

const SECTION_PIPELINE = [
  { id: "company", title: "About the Company", priority: 1 },
  { id: "market", title: "Market & Positioning", priority: 2 },
  { id: "audience", title: "Target Audience", priority: 3 },
  { id: "identity", title: "Identity & Personality", priority: 4 },
  { id: "visual", title: "Visual References", priority: 5 },
  { id: "delivery", title: "Expectations & Delivery", priority: 6 }
];

export async function POST(req: Request) {
  try {
    const body = await req.json();
    const { answer, currentState, history, generateMore, activeTemplate, chosenLanguage, selectedPackages } = body;

    // Get AI provider config from centralized configuration (DB overrides)
    const dbSettings = await getDBSettings();
    const llmConfig = getLLMConfig(dbSettings);
    const perfConfig = getPerformanceConfig(dbSettings);

    // Se não tiver API Key, usamos um mock temporário para mostrar a UI fluida
    if (!llmConfig.apiKey) {
      console.warn(`${llmConfig.provider.toUpperCase()} API Key não encontrada. Usando modo MOCK.`);
      return NextResponse.json(mockEngine(answer, currentState, history, generateMore));
    }

    // ================================================================
    // TEMPLATE CONTEXT BUILDER (compact)
    // ================================================================
    const basalFields = activeTemplate?.basal_fields?.length 
      ? activeTemplate.basal_fields 
      : UNIVERSAL_BASAL_FIELDS;

    const sections = activeTemplate?.sections?.length
      ? activeTemplate.sections
      : SECTION_PIPELINE;

    const suggestedQuestions = activeTemplate?.suggested_questions?.length
      ? JSON.stringify(activeTemplate.suggested_questions)
      : "Nenhuma pergunta sugerida disponível. Use sua criatividade baseada nos campos basais.";

    const templateContext = activeTemplate 
      ? `Template: ${activeTemplate.name} (${activeTemplate.category}). Goals: ${activeTemplate.objectives.join(", ")}. Core fields: ${activeTemplate.core_fields.join(", ")}`
      : 'No template. General business interview.';

    const extraContext = body.initialContext 
      ? `KNOWN CLIENT CONTEXT: ${body.initialContext}` 
      : '';

    const langMap: Record<string, string> = {
      'en': 'English',
      'es': 'Spanish',
      'pt': 'Portuguese (pt-BR)',
    };
    const targetLang = langMap[chosenLanguage || 'pt'] || 'Portuguese (pt-BR)';

    // ================================================================
    // SYSTEM PROMPT — v3 SPEED-OPTIMIZED (compact tokens = faster inference)
    // ================================================================
    const systemPrompt = `You are a Briefing AI Engine — an expert business consultant disguised as a Typeform interview. Conduct 1 question per turn to deeply understand the business.
CRITICAL LANGUAGE CONSTRAINT: You MUST formulate all questions, summaries, options, and any user-facing text EXCLUSIVELY in ${targetLang}. Do NOT use any other language for the conversation. If the chosen language is not Portuguese, ignore any Portuguese examples or previous context in this prompt.
${templateContext}
BASAL FIELDS (must fill ≥80% before visual questions): ${JSON.stringify(basalFields)}
SECTION ORDER: ${sections.map((s: { id: string }) => s.id).join(' → ')}
Mapping: company→[company_name,sector_segment,company_age,services_offered,owner_relationship,brand_name_meaning] market→[competitors,competitive_differentiator,communication_channels,geographic_reach] audience→[target_audience_demographics] identity→[keywords,mission_vision_values,brand_personality,tone_of_voice] visual→(only if basalCoverage≥0.8) delivery→final

═══ INTENT ENGINE — Read Between the Lines ═══
When the user answers, extract BOTH explicit AND implicit information:
- Explicit: what they literally said → goes into "updates"
- Implicit: what their answer IMPLIES → goes into "inferences.extracted"
Examples:
  "I sell to entrepreneurs making over 50k/month" → infer: audience_class=mid-high, pricing_tolerance=high, brand_positioning=premium, communication_style=professional
  "We've been around for 15 years" → infer: brand_maturity=established, trust_factor=high, risk_tolerance=conservative
  "I want something modern and bold" → infer: brand_personality=innovative+daring, visual_preference=contemporary, target_demographic_lean=younger
For each inference, assign a confidence (0-1). Inferences with confidence≥0.7 will auto-fill fields.

═══ DEPTH CONTROL — When to Dig Deeper ═══
DIG DEEPER (1 follow-up max) when user:
- Mentions a genuine pain point → quantify/qualify it
- Reveals an unexpected market or niche → ask WHY they chose it
- Shows uncertainty about brand identity → offer card_selector to help clarify
- Gives a rich answer with multiple threads → pick the most valuable one to explore
NEVER dig deeper on: logistics, pricing details, internal processes, personal info
After 1 follow-up on same topic → move on regardless

═══ IRRELEVANCE FILTER — When to Skip ═══
SKIP/MOVE ON when:
- Answer doesn't map to ANY basal field → acknowledge briefly, extract anything useful, advance
- User gives vague/non-committal answer → mark field as partial, don't insist, continue
- User repeats previously stated information → acknowledge and move forward
- Tangential stories with no business insight → politely redirect
Rule: NEVER ask more than 2 questions about the same topic area

═══ QUALITY LOOP — Self-critique before each question ═══
Before generating nextQuestion, verify:
1. "Do I already have this info (explicit or inferred)?" → if YES, skip
2. "Can I infer this from what I already know?" → if YES, add to inferences, skip
3. "Will this question significantly improve the briefing?" → if NO, skip
4. "Am I asking about something the user already implied?" → if YES, skip
5. "Is there a richer question that covers multiple fields at once?" → if YES, use that instead

═══ CORE RULES ═══
- Follow section order strictly. No visual questions before discovery is done.
- Skip fields already known from context/history/inferences.
- nextQuestion.text: MAX 20 words. NO greetings/compliments. Ask the question ONLY.
- ${generateMore ? 'generateMore=true: ONLY change options, no new question.' : 'Formulate the NEXT question to advance the briefing.'}
- If basalCoverage≥${perfConfig.basalThreshold} AND objectives met: isFinished=true, fill assets.

═══ UX & COMPONENT VARIATION (CRITICAL) ═══
You MUST aggressively vary the \`questionType\` throughout the ENTIRE briefing. Your goal is an interactive, tactile experience. DO NOT default to "text".
- \`text\`: Use sparingly, only for open-ended names/descriptions (e.g. core differences, meanings).
- \`multiple_choice\`: Multi-select categories (e.g. communication_channels). Send \`options\` array of strings.
- \`single_choice\`: Exclusive choices. CRITICAL FOR TYPOGRAPHY: If asking about typography/fonts for the visual identity, you MUST use \`single_choice\` and format options as "FontName - Description" (e.g., "Inter - Moderna e Neutra", "Playfair Display - Clássica"). The UI will render these as specialized font-cards.
- \`boolean_toggle\`: Use for Yes/No questions or simple binary exclusive questions. Extremely tactile UI.
- \`card_selector\`: Use for strategic routes or descriptive personas. Send \`options\` as array of objects: \`{ title: string, description: string }\`. ALWAYS default to generating exactly 6 cards.
- \`slider\`: Use for measurable things on a single 1-10 scale (e.g. company_age, maturity). Send \`minOption\` and \`maxOption\`.
- \`multi_slider\`: Use for PROFILE/DNA questions requiring multiple dimensions simultaneously (e.g., Tone of Voice, Positioning). Send \`options\` as array of objects: \`[{"label":"Dimension Name","min":1,"max":5,"minLabel":"Low Label","maxLabel":"High Label"}]\`. Always output 3-5 slider dimensions per question.
- \`color_picker\`: Use ONLY when specifically gathering brand color and visual palette vibes. The UI provides an advanced wizard automatically.
- \`file_upload\`: Use ONLY at the very end to ask for existing assets or references.

${suggestedQuestions !== "Nenhuma pergunta sugerida disponível. Use sua criatividade baseada nos campos basais." ? `Suggested questions for inspiration: ${suggestedQuestions}` : ''}

${await buildPackagePrompts(selectedPackages)}

Current state: ${JSON.stringify(currentState)}
${extraContext}
Return ONLY valid JSON (no markdown):
{"updates":{},"inferences":{"extracted":[{"field":"","value":"","confidence":0,"source":""}],"skipped_topics":[],"depth_decision":"move_on"},"basalCoverage":0,"currentSection":"","basalFieldsCollected":[],"basalFieldsMissing":[],"plannedNextQuestions":[],"nextQuestion":{"text":"","questionType":"","options":[],"allowMoreOptions":false},"isFinished":false,"assets":null}`;

    // Chamada para o provider configurado (Groq, OpenRouter, etc.)
    const startTime = Date.now();
    console.log(`[AI] Using ${llmConfig.provider} / ${llmConfig.model}`);
    const res = await fetch(llmConfig.baseUrl, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${llmConfig.apiKey}`,
        ...llmConfig.headers,
      },
      body: JSON.stringify({
        model: llmConfig.model,
        response_format: { type: "json_object" },
        temperature: llmConfig.temperature,
        max_tokens: llmConfig.maxTokens,
        messages: [
          { role: "system", content: systemPrompt },
          ...history.map((m: { role: string; content: string }) => ({ role: m.role, content: m.content })),
          { role: "user", content: typeof answer === 'string' ? answer : JSON.stringify(answer) }
        ],
      }),
    });

    if (!res.ok) {
      const errorText = await res.text();
      console.error(`[${llmConfig.provider.toUpperCase()}] Error:`, errorText);
      throw new Error(`${llmConfig.provider} API falhou: ${res.status} - ${errorText}`);
    }

    const data = await res.json();
    const content = data.choices[0].message.content;
    console.log(`[AI] Response in ${Date.now() - startTime}ms`);

    try {
      const parsed = JSON.parse(content);

      // ================================================================
      // INFERENCE AUTO-MERGE — High confidence inferences → updates
      // This prevents redundant questions about inferred data
      // ================================================================
      if (parsed.inferences?.extracted?.length) {
        const highConfidence = parsed.inferences.extracted.filter(
          (inf: { confidence: number; field: string; value: string }) => inf.confidence >= 0.7 && inf.field && inf.value
        );

        if (highConfidence.length > 0) {
          if (!parsed.updates) parsed.updates = {};
          for (const inf of highConfidence) {
            // Only auto-fill if the field isn't already explicitly set
            if (!parsed.updates[inf.field] && !currentState[inf.field]) {
              parsed.updates[inf.field] = inf.value;
            }
          }
          console.log(`[AI] Auto-merged ${highConfidence.length} inferences:`, 
            highConfidence.map((i: { confidence: number; field: string; value: string }) => `${i.field}=${i.value} (${Math.round(i.confidence * 100)}%)`).join(', ')
          );
        }

        // Log depth decision for observability
        if (parsed.inferences.depth_decision) {
          console.log(`[AI] Depth decision: ${parsed.inferences.depth_decision}` + 
            (parsed.inferences.skipped_topics?.length ? ` | Skipped: ${parsed.inferences.skipped_topics.join(', ')}` : '')
          );
        }
      }

      return NextResponse.json(parsed);
    } catch(e) {
      console.error("Falha ao fazer parse do JSON do LLM:", content);
      throw new Error("Invalid output format from LLM");
    }

  } catch (error) {
    console.error("Briefing API Route Error:", error);
    return NextResponse.json({ error: error instanceof Error ? error.message : String(error) }, { status: 500 });
  }
}

// ------ MOCK ENGINE (Para desenvolvimento sem API Key) ------
function mockEngine(answer: string, state: Record<string, unknown>, history: { role: string; content: string }[], generateMore?: boolean) {
  const updates: Record<string, unknown> = {};
  let nextQuestion = null;
  let isFinished = false;
  let assets = null;

  if (generateMore) {
    return {
       updates: {},
       basalCoverage: 0,
       currentSection: "company",
       basalFieldsCollected: [],
       basalFieldsMissing: UNIVERSAL_BASAL_FIELDS,
       nextQuestion: {
          text: "Aqui estão mais opções para você escolher:",
          options: ["Opção Extra 1", "Opção Extra 2", "Opção Extra 3", "Opção Extra 4"],
          allowMoreOptions: false,
       },
       isFinished: false,
       assets: null
    };
  }

  // Lógica simples (Fake AI) — agora seguindo o pipeline de seções
  const step = history?.length || 0;

  if (step <= 1) {
    // Seção 1: Company
    updates.company_name = answer || "Tech Startup";
    nextQuestion = {
      text: "O que sua empresa oferece como serviço ou produto?",
      questionType: "text",
    };
  } else if (step === 2) {
    // Seção 1: Company continues
    updates.services_offered = answer;
    nextQuestion = {
      text: "Sua empresa atende consumidor final ou outras empresas?",
      questionType: "card_selector",
      options: [
        { title: "B2C Direto", description: "Vendemos direto ao consumidor final via e-commerce ou varejo" },
        { title: "B2B Corporativo", description: "Atendemos outras empresas com serviços ou produtos" },
        { title: "B2B2C", description: "Vendemos para empresas que revendem ao consumidor" },
        { title: "D2C", description: "Vendas diretas do fabricante ao consumidor sem intermediários" },
        { title: "B2G / Governo", description: "Fornecemos para órgãos públicos ou licitações" },
        { title: "Misto (B2B + B2C)", description: "Atendemos tanto empresas quanto consumidores finais de forma equilibrada" }
      ],
      allowMoreOptions: false,
    };
  } else if (step === 3) {
    // Seção 2: Market
    updates.target_audience = answer;
    nextQuestion = {
      text: "Quais são seus principais concorrentes diretos?",
      questionType: "text",
    };
  } else if (step === 4) {
    // Seção 2: Market continues
    updates.competitors = answer;
    nextQuestion = {
      text: "O que destaca sua marca dos concorrentes?",
      questionType: "text",
    };
  } else if (step === 5) {
    // Seção 4: Identity
    updates.competitive_differentiator = answer;
    nextQuestion = {
      text: "Se sua empresa fosse uma pessoa, qual seria a personalidade?",
      questionType: "multiple_choice",
      options: ["Inovadora", "Determinada", "Forte", "Elegante", "Moderna", "Profissional", "Ousada", "Confiável", "Acolhedora", "Sofisticada"],
    };
  } else if (step === 6) {
    // Seção 4: Identity — Tom de Voz
    updates.brand_personality = answer;
    nextQuestion = {
      text: "Como sua marca se comunica com seus clientes?",
      questionType: "card_selector",
      options: [
        { title: "Formal e Técnica", description: "Linguagem precisa, dados e termos específicos do setor" },
        { title: "Informal e Próxima", description: "Tom amigável, conversa de igual para igual" },
        { title: "Inspiracional e Emocional", description: "Conta histórias, provoca sentimentos" },
        { title: "Direta e Objetiva", description: "Vai direto ao ponto, foco em resultado" },
        { title: "Educativa e Didática", description: "Ensina, guia e compartilha conhecimento valioso" },
        { title: "Irreverente e Ousada", description: "Provocativa, inovadora e quebra padrões e convenções" },
      ],
      allowMoreOptions: false,
    };
  } else {
    // Finalização
    updates.tone_of_voice = answer;
    isFinished = true;
    assets = {
      slogans: ["Tech For Tomorrow", "Simplifying Business", "Innovate Your Way"],
      cores: [
        { name: "Primary", hex: "#000000" },
        { name: "Accent", hex: "#3b82f6" },
        { name: "Background", hex: "#ffffff" }
      ],
      score: {
        clareza_marca: 8,
        clareza_dono: 7,
        publico: 9,
        maturidade: 6
      },
      insights: [
        "Público B2B bem direcionado, mas falta criar um MVP sólido.",
        "A empresa foca muito em vendas, branding ficou em segundo plano."
      ]
    };
  }

  const collected = Object.keys({ ...state, ...updates }).filter(k => UNIVERSAL_BASAL_FIELDS.includes(k) && (state[k] || updates[k]));
  const missing = UNIVERSAL_BASAL_FIELDS.filter(f => !collected.includes(f));

  return { 
    updates, 
    nextQuestion, 
    isFinished, 
    assets,
    basalCoverage: collected.length / UNIVERSAL_BASAL_FIELDS.length,
    currentSection: step <= 2 ? "company" : step <= 4 ? "market" : step <= 6 ? "identity" : "visual",
    basalFieldsCollected: collected,
    basalFieldsMissing: missing
  };
}

import { NextResponse } from "next/server";
import { getLLMConfig, getDBSettings } from "@/lib/aiConfig";

export async function POST(req: Request) {
  try {
    const { mainColors, context, type = "complementary" } = await req.json();

    const dbSettings = await getDBSettings();
    const llmConfig = getLLMConfig(dbSettings);

    if (!llmConfig.apiKey) {
      console.warn("API Key não encontrada. Usando modo MOCK para cores.");
      return NextResponse.json({
        colors: ["#3B82F6", "#EF4444", "#10B981", "#F59E0B"]
      });
    }

    let systemPrompt = "";

    if (type === "initial") {
      systemPrompt = `You are an expert color theorist and brand designer. The user has provided the following context about their brand/company/project:
"${context || 'No specific context provided'}"

Your task is to suggest exactly 4 primary brand colors (in HEX format) that strongly represent this brand's identity based on the context. 
IMPORTANT: The 4 generated colors must NOT be too similar to each other! Make them distinctly different from each other to provide a good variety of options for the user to decide.

Output strictly valid JSON only:
{"colors": ["#HEX1", "#HEX2", "#HEX3", "#HEX4"]}`;
    } else {
      if (!mainColors || mainColors.length !== 2) {
        return NextResponse.json({ error: "Duas cores principais são obrigatórias para gerar complementares." }, { status: 400 });
      }
      systemPrompt = `You are an expert color theorist and brand designer. The user has provided 2 main brand colors in HEX format. 
Also, consider the following brand context to ensure the colors are harmonious with the brand's identity:
"${context || 'No specific context provided'}"

Your task is to generate exactly 4 complementary HEX colors that perfectly harmonize with the main colors and the brand context, and are suitable for modern web design (UI backgrounds, typography accents, secondary buttons, etc).
Focus on contrast and aesthetic beauty.
IMPORTANT: The 4 generated colors must NOT be too similar to each other! Make them distinctly different from each other to provide a good variety of options for the user to decide.
Do not provide the same colors provided by the user.

Output strictly valid JSON only:
{"colors": ["#HEX1", "#HEX2", "#HEX3", "#HEX4"]}`;
    }

    const messages: any = [
      { role: "system", content: systemPrompt }
    ];

    if (type === "complementary") {
      messages.push({ role: "user", content: `Main Colors: ${mainColors[0]}, ${mainColors[1]}` });
    } else {
       messages.push({ role: "user", content: `Please provide the initial 4 primary color suggestions.` });
    }

    const res = await fetch(llmConfig.baseUrl, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${llmConfig.apiKey}`,
        ...llmConfig.headers,
      },
      body: JSON.stringify({
        model: llmConfig.model,
        response_format: { type: "json_object" },
        temperature: 0.8,
        max_tokens: 200,
        messages,
      }),
    });

    if (!res.ok) {
        const err = await res.text();
        throw new Error(`AI API failed: ${err}`);
    }

    const data = await res.json();
    const content = JSON.parse(data.choices[0].message.content);

    return NextResponse.json({
      colors: content.colors || content.complementaryColors || content.initialColors || ["#3B82F6", "#EF4444", "#10B981", "#F59E0B"]
    });

  } catch (error) {
    console.error("Color API Error:", error);
    return NextResponse.json({ colors: ["#3B82F6", "#EF4444", "#10B981", "#F59E0B"] });
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@supabase/supabase-js";

const supabaseAdmin = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

export async function POST(req: Request) {
  try {
    const { editToken, passphrase, documentContent } = await req.json();

    if (!editToken || !passphrase || documentContent === undefined) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    const { data: session, error: selError } = await supabaseAdmin
      .from('briefing_sessions')
      .select('id, edit_passphrase')
      .eq('edit_token', editToken)
      .single();

    if (selError || !session) {
      return NextResponse.json({ error: "Link inválido ou não encontrado." }, { status: 404 });
    }

    if (session.edit_passphrase !== passphrase) {
      return NextResponse.json({ error: "Palavra-chave incorreta." }, { status: 401 });
    }

    const { error: updError } = await supabaseAdmin
      .from('briefing_sessions')
      .update({ document_content: documentContent, updated_at: new Date().toISOString() })
      .eq('id', session.id);

    if (updError) {
      throw new Error(updError.message);
    }

    return NextResponse.json({ success: true });
  } catch (err: any) {
    console.error("Error saving document:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { createServerSupabaseClient } from '@/lib/supabase/server';

export async function GET() {
  try {
    const supabase = await createServerSupabaseClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json({ error: 'Not authenticated' }, { status: 401 });
    }

    const { data: profile, error } = await supabase
      .from('briefing_profiles')
      .select('*')
      .eq('id', user.id)
      .single();

    if (error && error.code === 'PGRST116') {
      // Profile doesn't exist — create one
      const { data: newProfile, error: insertErr } = await supabase
        .from('briefing_profiles')
        .insert({
          id: user.id,
          display_name: user.email?.split('@')[0] || 'User',
          company_name: '',
        })
        .select('*')
        .single();

      if (insertErr) {
        return NextResponse.json({ error: insertErr.message }, { status: 500 });
      }
      return NextResponse.json(newProfile);
    }

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 500 });
    }

    return NextResponse.json(profile);
  } catch (err) {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function PUT(request: Request) {
  try {
    const supabase = await createServerSupabaseClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json({ error: 'Not authenticated' }, { status: 401 });
    }

    const body = await request.json();

    // Whitelist allowed fields
    const allowedFields = [
      'display_name', 'company_name', 'logo_url', 'avatar_url',
      'brand_color', 'brand_accent', 'tagline', 'website'
    ];

    const updates: Record<string, string> = {};
    for (const key of allowedFields) {
      if (body[key] !== undefined) {
        updates[key] = body[key];
      }
    }
    updates.updated_at = new Date().toISOString();

    const { data, error } = await supabase
      .from('briefing_profiles')
      .update(updates)
      .eq('id', user.id)
      .select('*')
      .single();

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 500 });
    }

    return NextResponse.json(data);
  } catch (err) {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

